function useForm<T>(initialValues: T) {
  const [values, setValues] = useState<T>(initialValues)

  const handleChange = (name: keyof T, value: T[keyof T]) => {
    setValues(prev => ({ ...prev, [name]: value }))
  }

  const reset = () => {
    setValues(initialValues)
  }

  return {
    values,
    handleChange,
    reset
  }
}

