interface DropdownProps {
  options: string[]
  value: string
  onChange: (value: string) => void
}

function Dropdown({ options, value, onChange }: DropdownProps) {
  const [isOpen, setIsOpen] = useState(false)

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' || e.key === ' ') {
      setIsOpen(!isOpen)
    }
  }

  return (
    <div className="relative">
      <button 
        className="border p-2 w-full text-left" 
        onClick={() => setIsOpen(!isOpen)}
        onKeyDown={handleKeyDown}
        aria-expanded={isOpen}
      >
        {value}
      </button>
      {isOpen && (
        <div className="absolute top-full left-0 right-0 border bg-white">
          {options.map(option => (
            <button 
              key={option} 
              className="block w-full p-2 text-left hover:bg-gray-100"
              onClick={() => { onChange(option); setIsOpen(false) }}
            >
              {option}
            </button>
          ))}
        </div>
      )}
    </div>
  )
}

